use tokio::task;
use futures::future::join_all;

async fn process_items(items: Vec<Item>) -> Vec<Result<Output, Error>> {
    let tasks: Vec<_> = items
        .into_iter()
        .map(|item| {
            task::spawn(async move {
                process_item(item).await
            })
        })
        .collect();

    join_all(tasks)
        .await
        .into_iter()
        .map(|r| r.unwrap())
        .collect()
}

