async_patterns.actor_pattern:
// Actor pattern with channels
use tokio::sync::mpsc;

enum ActorMessage {
    Increment,
    Decrement,
    GetCount(oneshot::Sender<i32>),
}

struct CounterActor {
    count: i32,
    receiver: mpsc::Receiver<ActorMessage>,
}

impl CounterActor {
    async fn run(mut self) {
        while let Some(msg) = self.receiver.recv().await {
            match msg {
                ActorMessage::Increment => self.count += 1,
                ActorMessage::Decrement => self.count -= 1,
                ActorMessage::GetCount(sender) => {
                    let _ = sender.send(self.count);
                }
            }
        }
    }
}

